import sys

def count_affordable_pairs(N, T, A):
    """Count the number of affordable pairs in the array A."""
    affordable_pairs = 0
    for i in range(N):
        for j in range(i + 1, N):
            if A[i] * A[j] <= T:
                affordable_pairs += 1
    return affordable_pairs

def main():
    """Read input from stdin and write the answer to stdout."""
    N, T = map(int, sys.stdin.readline().split())
    A = list(map(int, sys.stdin.readline().split()))
    affordable_pairs = count_affordable_pairs(N, T, A)
    print(affordable_pairs)

if __name__ == "__main__":
    main()
